var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"천천히… 숨을 들이마십니다.","JPN":"ゆっくりと……息を吸ってください。","ENG":"Now... slowly inhale.","TWN":"慢慢地……吸氣。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"침묵은 곧 고요요. 마음을 가라앉힘에 비로소 우리는 평온을 되찾을 것입니다.","JPN":"沈黙は静寂。心を落ち着かせると私たちは平穏を取り戻せるのです。","ENG":"Silence is serene, and only by calming our minds can we regain peace.","TWN":"沉默即是寧靜。只有心平氣和，我們才能重獲平靜。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"몸에 힘을 빼고… 웃으며 세 번 말합니다.","JPN":"体から力を抜いて……ほほ笑みながら3回唱えます。","ENG":"Relax all the tension in your body... and chant with me three times with a smile.","TWN":"放鬆身體……微笑著說三遍。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"나는 행복하다!","JPN":"私は幸せだ！","ENG":"I'm happy!","TWN":"我很幸福！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":" 나는 행복하다!","JPN":" 私は幸せだ！","ENG":" I'm happy!","TWN":"我很幸福！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":" 나는 행복하다!","JPN":" 私は幸せだ！","ENG":" I'm happy!","TWN":"我很幸福！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"시끄러워, 여기 너만 있냐?","JPN":"うるせえよ、ここにいるのはお前だけじゃねえぞ。","ENG":"Shut up. You think you own this place, huh?!","TWN":"閉嘴，這裡只有你嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_03"},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"행복하긴 개뿔. 하다못해 그 확성기 좀 끄란 말이야!","JPN":"幸せなはずねえだろ。いいかげんその拡声器はやめろよ！","ENG":"Happy, my foot. At least turn that stupid megaphone off!","TWN":"幸福個鬼，給我把把那個擴音器關掉！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"나는 행복하다. 나는 행복하다. 나는……","JPN":"私は幸せだ。私は幸せだ。私は……","ENG":"I'm happy. I'm happy. I'm...","TWN":"我很幸福。我很幸福。我很……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"subtitle","speaker":null,"text":{"KOREA":"그라운드 원. 카운터 범죄 수용소.\\n<color=#ffd34c>G1 보안교육대</color>.","JPN":"グラウンド・ワン。カウンター犯罪者収容所。\\n<color=#ffd34c>G1保安教育隊</color>。","ENG":"Ground One. Criminal Counter Prison.\\n<color=#ffd34c>G1 Security Education Center</color>.","TWN":"G1，制裁者罪犯收容所\\n<color=#ffd34c>安全教育中心</color>."},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"subtitle","speaker":null,"text":{"KOREA":"수감번호 24601. <color=#ffd34c>유피</color>.","JPN":"収容番号24601。<color=#ffd34c>ユピ</color>。","ENG":"Inmate No. 24601. <color=#ffd34c>Yuppie</color>.","TWN":"囚犯編號24601，<color=#ffd34c>悠菲</color>。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"불행해…….","JPN":"不幸だよ……","ENG":"I'm so miserable...","TWN":"不幸……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"심금을 울리는 목소리. 마드모아젤.","JPN":"心の琴線に触れる声。マドモアゼル。","ENG":"Your voice plucks my heartstrings, mademoiselle.","TWN":"真是動人心弦的聲音，小姐。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"죄를 뉘우치고자 하는 마음. 이 로저는 실로 존경스럽군요.","JPN":"罪を悔もうとするその心。このロジャーは大変尊敬しています。","ENG":"Your desire to repent for your sins. I, Roger, am truly impressed.","TWN":"你的懺悔之心，連我羅杰也感到敬佩。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"subtitle","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"수감번호 24600. <color=#ffd34c>로저</color>.","JPN":"収容番号24600。<color=#ffd34c>ロジャー</color>。","ENG":"Inmate No. 24600. <color=#ffd34c>Roger</color>.","TWN":"囚犯編號24600，<color=#ffd34c>羅杰</color>。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"필시 그 확성기는 회개를 위한 목어일 터.","JPN":"その拡声器はきっと懺悔のための木魚であるはず。","ENG":"That megaphone must be a wooden fish used in Buddhism for repentance.","TWN":"那個擴音器必定是為了懺悔而用的木魚吧。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"어… 아뇨? 그냥 성인마냥 주절대면 조금 해탈할 수 있지 않을까 싶었는데요.","JPN":"えっ……違います。聖人のようにそれっぽく呟いてれば、ちょっとは解脱できるんじゃないかと思って。","ENG":"Uh... No? I just thought that I'd feel a little liberated if I rambled on like a saint.","TWN":"呃……不是呀？我只是覺得像聖人一樣嘮叨幾句，或許能有點解脫感……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"마음에 확 와닿게 한달까. 제 카운터 능력이랑 연관 있거든요.","JPN":"それにこれが心にぐっとくるというか。私のカウンター能力と関係があるんですよね。","ENG":"I think I can reach enlightenment, or something. It's related to my Counter ability.","TWN":"說不定能有共鳴呢……這和我的制裁者能力有點關係。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"뭐, 감옥에 갇힌 시점에서 이제 와 무슨 소용이겠냐만.","JPN":"まあ、牢獄に閉じ込められてる時点で、今は何の役にも立ちませんけど。","ENG":"But what good is it now that I'm in prison?","TWN":"唉，都已經被關進監獄了，現在說什麼也沒用了。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"하루 아침에 범죄자가 되다니. 역시 사람 일은 모르고 볼 일이네요.","JPN":"まさか一朝一夕に犯罪者になるなんて。やっぱり人生ってわからないですね。","ENG":"Becoming a criminal overnight. Life really is full of surprises.","TWN":"一夜之間成了罪犯。果然世事難料啊。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"세상은 부조리함으로 가득합니다, 마드모아젤.","JPN":"世界は不条理に満ちています、マドモアゼル。","ENG":"The world is full of absurdity, mademoiselle.","TWN":"沒錯。這個世界充滿了不公，小姐。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"저만 하더라도 아이가 떨어진 사탕을 주워 먹는 걸 말렸다는 이유로 이곳에 왔지요.","JPN":"僕もまた、子どもが落とした飴を拾って食べようとするところを止めたという理由でここに来ました。","ENG":"Look at me. I was sent here because I stopped a kid from eating candy off the floor.","TWN":"我只不過是為了阻止孩子吃掉在地上的糖果，就被送到了這裡。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"그럴 수가 있나요?","JPN":"そんなことでですか？","ENG":"Can they even do that?","TWN":"怎麼會這樣呢……？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"제 얼굴을 본 아이가 울음을 터트렸습니다.","JPN":"僕の顔を見た子どもが泣き始めました。","ENG":"Well, the child burst into tears after seeing my face.","TWN":"那個孩子一看到我的臉就哭了。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"아이의 사탕을 뺏은 것처럼 보이는 거구… 남들이 보기엔 전 쓰레기였겠지요.","JPN":"子どもの飴を奪ったように見える巨漢……他人から見た僕はクズ同然だったのでしょう。","ENG":"It must have looked like a man was trying to steal candy from a baby... So to others, I must have looked like a piece of trash.","TWN":"不知道的人還以為是我搶了他的糖果……果然在別人眼裡，我就是個垃圾吧……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"이런 젠장!","JPN":"そんな！","ENG":"Dang it!","TWN":"太不公平了！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"세상 사람들은 억울한 사연에 귀 기울이지 않아요!","JPN":"世俗の人は誤解を受けた者の訴えには耳を傾けないのです！","ENG":"People won't even lend an ear to hear us out!","TWN":"根本沒人會來傾聽我們的冤屈！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"전… 전 그냥 배를 탔을 뿐이라고요!","JPN":"私は……ただ船に乗っていただけなんです！","ENG":"All... All I did was get on a boat!","TWN":"我……我只是上了艘船而已啊！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"진정하시죠, 마드모아젤. 적막한 감옥 안, 시간 이외에 달리 무엇이 남겠습니까?","JPN":"落ち着いてください、マドモアゼル。寂寞とした牢獄の中では時間以外には何も存在しません。","ENG":"Calm down, mademoiselle. We have nothing but time in this deafening prison.","TWN":"冷靜點，小姐。在這個寂靜的牢房裡，最不缺的便是時間……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"당신의 슬픔을 들려주시지요.","JPN":"あなたの悲哀をお聞かせください。","ENG":"Tell me your sorrows.","TWN":"請告訴我你的悲傷吧。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"이 로저. 기꺼이 함께 나누겠습니다.","JPN":"このロジャー、喜んで分かち合いましょう。","ENG":"I, Roger, will gladly share the burden.","TWN":"我，羅杰，樂意與你分享一切。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"아아, 로저…….","JPN":"ああ、ロジャー……","ENG":"Ah, Roger...","TWN":"啊啊，羅杰……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"조금 길어질 텐데 괜찮을까요?","JPN":"ちょっと長くなりますけど、大丈夫ですか？","ENG":"Are you sure? It may be a little long.","TWN":"故事可能會有點長，可以嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"물론입니다, 마드모아젤.","JPN":"もちろんです、マドモアゼル。","ENG":"Please, mademoiselle.","TWN":"當然可以，小姐。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROGER_DEBT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"시작은 평범했어요.","JPN":"始まりはいたって平凡なものした。","ENG":"It started out like any other day.","TWN":"起初很普通。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"시설에 돈이 없다는 원장님의 말을 듣고 일을 시작했을 뿐이거든요.","JPN":"施設にお金がないという院長の話を聞いて、仕事を始めただけだったんです。","ENG":"All I did was start working because the headmaster told me that we ran out of money.","TWN":"我只是聽院長抱怨說沒錢了才開始打工的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"원장님이요?","JPN":"院長とは？","ENG":"Headmaster?","TWN":"院長？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"아, 전 보육원 출신이에요. 시설 아이들 중에서 나이가 많은 편이라 동생들을 돌보는 쪽에 가깝지만.","JPN":"あ、私は孤児院出身です。施設の子どもたちの中では年長組だったから、みんなのお世話をしていたんですけど。","ENG":"Oh, I'm from an orphanage. But because I'm older than most of the kids there, I usually take care of them.","TWN":"啊，我是在育幼院長大的。在育幼院的孩子當中，我算是年紀比較大的，所以更像是照顧弟弟妹妹的大姊姊。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_CHILD"},{"id":"L4_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"받은 은혜가 있으니 가만히 있기 뭐했고, 당장 시설 아이들이 굶을 수도 있으니까.","JPN":"施設には恩があるから何もしないわけにもいかなかったし、子どもたちが飢えてしまうかもしれなかったから。","ENG":"I didn't want to be ungrateful and do nothing. And I didn't want the kids there to starve.","TWN":"畢竟受了院長的恩惠，坐視不理也不好，況且育幼院的孩子們會餓肚子。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"결국 도움이라도 되자는 마음으로 시작한 출가가… 동시에 놈들과의 악연의 시작이었죠.","JPN":"何か役にでも立とうと思って始めた出稼ぎが……やつらとの腐れ縁の始まりだったんです。","ENG":"So I left to make money and be helpful to the kids. And that... was the start of this terrible relationship with \\"them.\\"","TWN":"最終為了幫忙而決定去打工……同時也是與那些傢伙結下惡緣的開始。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L7_1","type":"dialog","speaker":"ROGER_DEBT_NPC_NULL","text":{"KOREA":"놈들이라니? 대체 누굴 말하시는 거죠?","JPN":"やつらとは誰のことでしょうか？","ENG":"Them? Who are you talking about?","TWN":"那些傢伙？他們究竟是誰？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"시그마 해적단.","JPN":"シグマ海賊団。","ENG":"The Sigma Pirates.","TWN":"西格瑪海盜團。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"오늘도 고생하셨어요~ 유피 씨가 온 뒤로 매출이 꾸준히 상승세예요♬","JPN":"今日もお疲れさまでした～ユピさんが来てから、売り上げはうなぎ上りですよ♬","ENG":"Great work today! Since Yuppie joined, sales have been steadily increasing♬","TWN":"今天也辛苦了～自從悠菲來了之後，銷售額一直穩定上升呢♬"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"역시~ 제가 잘 가르쳐준 덕분일까요? 후훗.","JPN":"やっぱり～私の教え方が上手いからでしょうか？　ふふっ。","ENG":"And it's all because I taught her well, no? Fu fuu.","TWN":"果然～是不是因為我教得好呢？嘿嘿嘿。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"발주나 좀 제대로 해주세요, 선배. 그 이상한 펭귄 옷은 어디서 가져오시는 거예요?","JPN":"ちゃんと発注してくださいよ、先輩。その変なペンギンコスチュームはどこから持って来たんですか？","ENG":"Will you please place the orders correctly? And, where did you even find that weird penguin suit?","TWN":"前輩，拜託你好好訂貨吧。還有那個奇怪的企鵝裝是從哪裡弄來的？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"아무리 다른 지점에서 나온 임시 파견직이라도 너무 제멋대로잖아요.","JPN":"別の支店からの臨時派遣だからって、勝手すぎるんじゃないですか。","ENG":"Even if you're only temporarily here from another branch, you're so capricious.","TWN":"即使你是從其他分店臨時派來的，也不能這麼隨便吧。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"에이~ 이렇게 보여도 전 지점의 핵심 상품이랍니다?","JPN":"ええ～変って言うけど、前の支店のメイン商品ですよ？","ENG":"Oh, come on. It might look weird, but it was a core product at our branch, you know?","TWN":"欸？雖然看起來這樣，但這個可是店裡的核心商品喔？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"옷의 원재료를 저희 편의점에서만 특별 취급했거든요.","JPN":"コスチュームの材料を、私のコンビニだけで特別に扱っていたんです。","ENG":"The textile used for the suit was only available in our convenience stores.","TWN":"衣服的原材料只有我們便利商店能特別處理。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"유피 씨도 몇 개 가져가보세요~ 동생분들한테 입히면 분명 귀여울걸요?","JPN":"ユピさんもいくつか持ち帰ってみたらどうですか～？　弟や妹に着せたら、きっと可愛いですよ。","ENG":"You should take a few, Yuppie! I'm sure the kids will look so cute in them!","TWN":"悠菲也拿幾件試試吧～給弟弟妹妹們穿上一定很可愛吧？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"상품이 문제라는 게 아니에요. 선배가 수선 비용으로 코코넛만 받아오는 게 문제지.","JPN":"商品が問題なんじゃなくて、先輩が修繕費としてココナッツばっかりもらってくるのが問題なんです。","ENG":"The product isn't the issue. It's that you're taking coconuts as payment for alterations.","TWN":"我說的不是商品……問題是前輩只收椰子作為修繕費用。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"점장님이 매출 관련해서 얼마나 저를 들들 볶는지 아세요?","JPN":"店長が売り上げのことで私にいちゃもんつけるんですよ。","ENG":"Do you know how much the manager nags me about our revenue?","TWN":"你知道店長一天到晚都在唸我銷售額的事嗎？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"힘드시겠다~ 원래 일을 하다 보면 힘든 일이 이만저만이 아니죠.","JPN":"大変そう～。仕事って、辛いことが色々ありますもんね。","ENG":"That must be so hard...! But you're bound to run into difficult situations when working.","TWN":"那一定很辛苦～不過工作本來就有很多不容易的地方……"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"하지만 괜찮아요. 저도 예전에는 제 할 일만 겨우 해낼 정도로 미숙했지만……","JPN":"でも大丈夫ですよ。私も昔は自分の仕事だけで精一杯で未熟だったけど……","ENG":"It's okay, though. I was also once inexperienced and barely finished my own work...","TWN":"但是沒關係，我在新人時期也是每天都被唸……"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"이제는 <color=#ffd34c>이렇게 할 거면 네가 점장하라</color>는 소리까지 듣는 걸요?","JPN":"今は<color=#ffd34c>お前が店長をやれ</color>って言われるほどになったんですよ。","ENG":"But now, I hear people tell me, <color=#ffd34c>\\"Why don't you just take over the store if you're going to keep working like that?!\\"</color>","TWN":"現在意見多到，店長都跟我說<color=#ffd34c>你這麼會，那店長給你當吧</color>？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"선배. 제 말 들으신 거 맞죠?","JPN":"先輩。私の話、聞いてました？","ENG":"Serina, did you even hear what I said?","TWN":"前輩，你有在聽我說話吧！？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"그럼요~. 후배의 상담을 받아주는 게 제 꿈이었거든요~♬","JPN":"もちろんですよ～。後輩の相談を聞いてあげるのが私の夢でしたから♬","ENG":"Of course! It's been my dream to consult juniors like you ♬","TWN":"當然啦～聆聽後輩的煩惱可是我的夢想呢～♬"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"에휴…….","JPN":"はあ……","ENG":"*Sigh*","TWN":"唉……"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"아무튼 조심 좀 해주세요. 선배랑 달리 전 점장님 눈칫밥 먹느라 죽을 것 같다고요.","JPN":"とにかく、気をつけてくださいね。先輩と違って、私は店長の機嫌をとるので大変なんですから。","ENG":"Anyway, please be more careful. Unlike you, I dread having to walk on eggshells in front of the manager.","TWN":"總之請用點心，我和前輩不同，我快要被店長的眼神給殺死了。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"걱정 마세요. 연차만 쌓이면 누구나 잘 할 수 있게 되는 걸요?","JPN":"心配しないでください。長く働けば、誰でもちゃんとできるようになります。","ENG":"Don't worry. Everyone gets better at their job with more experience.","TWN":"別擔心。只要積累經驗，就會越做越好啦～？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"그 얘기가 아니라 돈 말이예요, 돈.","JPN":"その話じゃなくて、お金です。お金。","ENG":"I'm talking about money here.","TWN":"不是那個意思，我是說錢，錢啦！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"선배는 부잣집 영애잖아요? 편의점 일을 하는 것도 서민체험의 일부라 하셨고.","JPN":"先輩はお金持ちのご令嬢でしょう？　コンビニの仕事をしてるのも庶民体験の一部だって言ってたし。","ENG":"You're from a wealthy family, right? And you're only working at a convenience store to experience how the working class lives.","TWN":"前輩是富家千金吧？在便利商店工作也是體驗平民生活的一部分？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"선배 입장에서는 푼돈일지 몰라도, 전 월급 한 번이 귀중하다고요.","JPN":"先輩から見たらはした金かもしれませんけど、私には貴重な給料なんです。","ENG":"So the money may not be a lot to you, but every cent in my paycheck is precious to me.","TWN":"對前輩來說可能是小錢，但對我來說每個月的工資都很重要。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"으음… 시설 상황이 많이 안 좋나요?","JPN":"うーん……施設の状況がそんなによくないのですか？","ENG":"Mm... Is the orphanage not doing so well?","TWN":"嗯……育幼院的情況很糟糕嗎？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"원장님이 눈치 보면서도 저한테 부탁하셨을 정도니까요. 제법 아슬아슬한 모양이에요.","JPN":"院長が恐る恐る私に頼んだくらいですからね。結構ギリギリみたいです。","ENG":"Seeing how the headmaster had to ask me for help, I don't think so.","TWN":"院長都小心翼翼地拜託我了。看來情況相當緊急。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"아아~ 어디 크게 한탕 할 만한 일이 있으면 좋으련만.","JPN":"あ～あ、どっかに一儲けできる仕事があったらいいのになあ。","ENG":"Aaah... I wish there was a way to get some quick cash.","TWN":"啊……要是有個大賺一筆的機會就好了。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"아, 그럼 이런 건 어떠세요?","JPN":"あ、ではこれはどうですか？","ENG":"Oh! Then what about something like this?","TWN":"啊，我想起來了！"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"큰 일은 아니지만, 실은 얼마 전에 다른 지점의 구인공고가 올라왔거든요.","JPN":"大きな仕事ではないですけど、実はこの前に別の支店から求人広告が出たんです。","ENG":"It's nothing big, but another branch recently posted a job ad.","TWN":"雖然不是什麼大事，但前不久其他分店有貼出職缺。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"편의점 아포칼립스… 프론트베이 지부?","JPN":"コンビニアポカリプス……フロントベイ支部？","ENG":"Apocalypse Convenience Store... Front Bay branch?","TWN":"便利商店 阿波卡利斯……前灣分店？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"이번에 각 지점에서 추천된 인재들로 시범운영을 한다고 하더라고요.","JPN":"今度、各支店から推薦された人たちでテスト運営をするらしいです。","ENG":"They said they are conducting a trial run with recommended employees from each branch.","TWN":"這次好像是各個分店推薦人才過去進行試運營。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"일은 힘들어도 시급이 두 배라는데, 유피 씨 정도면 충분히 해볼 만하지 않을까요?","JPN":"仕事はきついですけど時給が2倍だって言うし、ユピさんなら十分いけるのではないでしょうか？","ENG":"Work might be harder, but it's double the hourly pay. So, what do you think, Yuppie?","TWN":"雖然工作很辛苦，但時薪是雙倍的，悠菲應該可以勝任吧？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"점장님도 사정을 아시는 만큼 추천을 받는 건 어렵지 않을 거예요.","JPN":"店長も事情をご存じですから、推薦してくれるはずです。","ENG":"Since the manager also knows about your circumstances, I'm sure it won't be difficult to get her to recommend you.","TWN":"店長也了解你的情況，應該會願意推薦你。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"저, 선배.","JPN":"あの、先輩。","ENG":"Really, Serina?","TWN":"我……前輩……"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"도착했다. 여기가…….","JPN":"着いた。ここが……","ENG":"I'm here. So this is...","TWN":"到了。這裡就是……"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_DEBT_NULL_NULL","text":{"KOREA":"프론트베이구나.","JPN":"フロントベイか。","ENG":"Front Bay.","TWN":"前灣啊。"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};